// Simulate OCR processing
// Assuming input contains file info
// For demo, we set static OCR result as in original JSON
return [{
  ...$json,
  ocr: {
    engine: "tesseract",
    language: "spa",
    confidence_avg: 0.87,
    raw_text: "BOLETA ELECTRONICA\nFolio: 123456\nFecha: 04-05-2026\nRUT Emisor: 76.123.456-7\nProveedor Demo SPA\nSubtotal: 8.403\nIVA: 1.597\nTOTAL: 10.000\nMedio de pago: Debito"
  }
}];

// Extract structured data from OCR raw text
// In real scenario, you would parse the raw_text
// For demo, we set static extracted data as in original JSON
return [{
  ...$json,
  extracted_data: {
    document_type: "boleta",
    folio: "123456",
    issue_date: "2026-05-04",
    issuer_name: "Proveedor Demo SPA",
    issuer_rut: "76.123.456-7",
    currency: "CLP",
    subtotal: 8403,
    tax: 1597,
    total: 10000,
    payment_method: "debito"
  }
}];

// Validation rules
const errors = [];
const data = $json.extracted_data;
if (parseFloat(data.subtotal) + parseFloat(data.tax) !== parseFloat(data.total)) {
  errors.push('total_equals_subtotal_plus_tax');
}
// Simple RUT format check (contains hyphen and dots)
if (!/^[0-9]{1,2}(\.?[0-9]{3}){2}-[0-9kK]$/.test(data.issuer_rut)) {
  errors.push('issuer_rut_format_valid');
}
if (!data.issue_date) {
  errors.push('issue_date_present');
}
return [{
  ...$json,
  validation: {
    status: errors.length === 0 ? 'valid' : 'invalid',
    rules_applied: [
      { rule: 'total_equals_subtotal_plus_tax', result: errors.indexOf('total_equals_subtotal_plus_tax') === -1 },
      { rule: 'issuer_rut_format_valid', result: errors.indexOf('issuer_rut_format_valid') === -1 },
      { rule: 'issue_date_present', result: errors.indexOf('issue_date_present') === -1 }
    ],
    observations: errors
  }
}];
